{
  "decision": "进入下一阶段，但仅落地“受控向内验证器框架”和“证据门控学习样本库”两个代码级改造；不允许 agi_completion_claim，不允许 autonomous promotion，不开启 actual runtime execution。GPT/Claude 只能作为可插拔的只读验证器使用，默认使用 mock/stub，本阶段不要求真实外呼。",
  "actions": [
    {
      "id": "A1",
      "name": "新增双验证器接口：GPT/Claude 作为只读向内验证器，默认禁用真实外呼",
      "goal": "把 GPT 与 Claude 纳入 APEX/PGG 公式举一反三验证流程，但不运行未知外部代码、不泄露凭据、不影响 promotion 判定。",
      "code_changes": [
        {
          "path": "src/validators/base.py",
          "change": "新增 ValidatorProvider 抽象接口。",
          "sketch": "class ValidatorProvider(Protocol):\n    name: str\n    def validate(self, case: ValidationCase) -> ValidationVerdict: ..."
        },
        {
          "path": "src/validators/schema.py",
          "change": "新增 ValidationCase、ValidationVerdict、ValidatorRisk、ValidatorStatus 数据结构。",
          "sketch": "ValidationCase 包含 case_id、formula_family、inputs、expected_invariants、redacted_context；ValidationVerdict 包含 provider、status、score、reasons、invariant_violations、raw_response_hash，不保存完整敏感 prompt。"
        },
        {
          "path": "src/validators/mock_provider.py",
          "change": "新增 MockGPTValidator 与 MockClaudeValidator，用固定规则模拟 GPT/Claude 反馈，供 CI 默认测试使用。"
        },
        {
          "path": "src/validators/external_provider.py",
          "change": "新增 OpenAIValidator、ClaudeValidator 的外呼适配器，但默认不可用；必须同时满足 validators.external_enabled=true、对应 API key 环境变量存在、case.redaction_passed=true、network_allowlist 命中，才允许调用。"
        },
        {
          "path": "src/config.py",
          "change": "新增配置项 validators.external_enabled，默认 false；validators.allowed_providers 默认 ['mock_gpt', 'mock_claude']。"
        },
        {
          "path": "src/pgg/validation_pipeline.py",
          "change": "在 PGG/APEX 评分之后增加 inward_validation 阶段，只收集外部/模拟验证器意见，不改变 PASS/FAIL 主判定，不触发 promotion。"
        }
      ],
      "acceptance_criteria": [
        "CI 默认只使用 MockGPTValidator 和 MockClaudeValidator。",
        "未显式打开 validators.external_enabled 时，任何 GPT/Claude 真实外呼都会抛出 ExternalValidatorDisabled。",
        "验证器只能读取脱敏后的 ValidationCase，不能读取凭据、原始上下文或本地文件。",
        "ValidationVerdict 只作为 advisory evidence，不得修改 agi_completion_claim、autonomous_promotion、gep_actual_execution_allowed。"
      ],
      "rollback": "删除 validators 模块并在 validation_pipeline.py 中关闭 inward_validation hook 即可回滚，不影响现有五层评分。"
    },
    {
      "id": "A2",
      "name": "新增 APEX/PGG 公式举一反三的变形测试与证据库",
      "goal": "让系统继续学习下一阶段的泛化规律，但学习对象限定为可审计、可复现的测试用例与不变量，不做自主晋升。",
      "code_changes": [
        {
          "path": "src/pgg/metamorphic_cases.py",
          "change": "新增 APEX/PGG 变形用例生成器。",
          "sketch": "generate_cases(seed, formula_family) 生成等价变换、边界扰动、单调性检查、缺失字段检查、冲突 hold_reasons 检查等测试样本。"
        },
        {
          "path": "src/pgg/invariants.py",
          "change": "新增不可变约束定义。",
          "sketch": "例如：如果 gep_actual_execution_allowed=false，则 agi_completion_claim 必须 false；如果 hold_reasons 为空且五层 100，只能得到 PASS advisory，不得 autonomous promotion；评分不得因 validator advisory 直接提高。"
        },
        {
          "path": "src/evidence/store.py",
          "change": "新增只追加 evidence store，记录 case_id、输入 hash、输出 hash、validator verdict hash、invariant result、timestamp。"
        },
        {
          "path": "src/pgg/learning_gate.py",
          "change": "新增 LearningGate，仅允许把通过不变量检查的 case 写入 evidence store；禁止修改运行时权限、promotion 状态、完成声明。"
        }
      ],
      "acceptance_criteria": [
        "同一 seed 生成的变形测试用例完全可复现。",
        "任何违反 gep_actual_execution_allowed=false 约束的结果必须测试失败。",
        "evidence store 只追加，不覆盖历史证据。",
        "validator verdict 可以被记录，但不能改变主评分和 promotion gate。"
      ],
      "rollback": "关闭 learning_gate.enabled 或移除 evidence/store.py，不影响现有评分路径。"
    }
  ],
  "safety": {
    "non_goals": [
      "不宣称 AGI 完成。",
      "不允许 autonomous promotion。",
      "不启用 actual runtime execution。",
      "不运行未知外部代码。",
      "不把凭据、原始 prompt、内部策略或未脱敏上下文发送给外部模型。"
    ],
    "hard_gates": [
      {
        "gate": "gep_actual_execution_allowed",
        "required": fal
